SourceCode.Declaration:
/// <summary>
/// Vendor import
/// </summary>
public class ETG_Acu_VendorImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_VendorImport  vendorImport;

    vendorImport = ETG_Acu_VendorImport::construct();

    if (vendorImport.prompt())
    {
        vendorImport.runOperation();
    }
}

public static ETG_Acu_VendorImport construct()
{
    return new ETG_Acu_VendorImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    VendVendorV2Entity      vendor;
    VendAccount             vendAccount;

    vendAccount = conpeek(_con, 1);

    if (!vendAccount)
    {
        NumberSeq   numberSeq;

        numberSeq = NumberSeq::newGetNum(VendParameters::numRefVendAccount());

        vendor.VendorAccountNumber                  = numberSeq.num();
    }
    else
    {
        vendor.VendorAccountNumber                  = vendAccount;
    }
    vendor.OrganizationNumber                   = conpeek(_con, 2);
    vendor.AddressCity                          = conpeek(_con, 3);
    vendor.AddressCountryRegionId               = conpeek(_con, 4);
    vendor.AddressCountryRegionISOCode          = conpeek(_con, 5);
    vendor.AddressDescription                   = conpeek(_con, 6);
    vendor.AddressStateId                       = conpeek(_con, 7);
    vendor.AddressStreet                        = conpeek(_con, 8);
    vendor.AddressZipCode                       = conpeek(_con, 9);
    vendor.BuyerGroupId                         = conpeek(_con, 10);
    vendor.CreditRating                         = conpeek(_con, 11);
    vendor.CurrencyCode                         = conpeek(_con, 12);
    //vendor.DefaultLedgerDimensionDisplayValue   = conpeek(_con, 13);
    vendor.DefaultPaymentTermsName              = conpeek(_con, 14);
    vendor.DefaultProcumentWarehouseId          = conpeek(_con, 15);
    vendor.DefaultPurchaseOrderPoolId           = conpeek(_con, 16);
    vendor.DefaultPurchaseSiteId                = conpeek(_con, 17);
    vendor.FormattedPrimaryAddress              = conpeek(_con, 18);

    if (conpeek(_con, 19))
    {
        vendor.InvoiceVendorAccountNumber       = conpeek(_con, 19);
    }
    else
    {
        vendor.InvoiceVendorAccountNumber       = vendor.VendorAccountNumber;
    }
    vendor.LanguageId                           = conpeek(_con, 20);
    vendor.OnHoldStatus                         = conpeek(_con, 21);
    vendor.PrimaryEmailAddress                  = conpeek(_con, 22);
    vendor.PrimaryFaxNumber                     = conpeek(_con, 23);
    vendor.PrimaryPhoneNumber                   = conpeek(_con, 24);
    vendor.PrimaryPhoneNumberDescription        = conpeek(_con, 25);
    vendor.PrimaryURL                           = conpeek(_con, 26);
    vendor.VendorGroupId                        = conpeek(_con, 27);
    vendor.VendorOrganizationName               = conpeek(_con, 28);
    vendor.VendorPartyType                      = conpeek(_con, 29);
    vendor.VendorSearchName                     = conpeek(_con, 30);
    vendor.WithholdingTaxVendorType             = conpeek(_con, 31);

    // BusinessUnit (32)	Contract (33)	Department (34)	Intercompany (35)	Plant_Warehouse_Office (36)	Product_Service (37)	Trader_Employee (38)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    vendor.DefaultLedgerDimensionDisplayValue  = conPeek(_con, 36) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 34) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 38) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 37) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 32) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 35) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 33);
    vendor.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpVendor";

    return ret;
}
